import React, { useState, useEffect } from 'react';
import AOS from 'aos';
import 'aos/dist/aos.css';

// Component Imports
import Hero from './components/sections/Hero';
import FlowerPetals from './components/animations/FlowerPetals';
import Countdown from './components/ui/Countdown';
import Timeline from './components/sections/Timeline';
import Gallery from './components/sections/Gallery';
import RSVPForm from './components/sections/RSVPForm';
import InvitationQR from './components/ui/InvitationQR';
import MusicPlayer from './components/ui/MusicPlayer';
import Navbar from './components/ui/Navbar';
import ThreeRings from './components/animations/ThreeRings';
import Profiles from './components/sections/Profiles';
import VenueMap from './components/ui/VenueMap';
import Events from './components/sections/Events'; // New
import GiftRegistry from './components/sections/GiftRegistry'; // New
import Guestbook from './components/ui/Guestbook';
import ParallaxSection from './components/animations/ParallaxSection';
import GlassCountdown from './components/ui/GlassCountdown';
import FloatingActions from './components/ui/FloatingActions';
import StyleGuide from './components/sections/StyleGuide';
import LiveCounter from './components/ui/LiveCounter';
import SuccessModal from './components/ui/SuccessModal';

function App() {
  const [submittedData, setSubmittedData] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    try {
      AOS.init({ 
        duration: 1000, 
        once: true,
        offset: 50,
        disable: window.innerWidth < 768 
      });
      AOS.refresh();
    } catch (e) {
      console.error("AOS init error:", e);
    }
  }, []);

  return (
    <div className="bg-[#FAF9F6] min-h-screen selection:bg-luxury-gold selection:text-white">
      <Navbar />
      <MusicPlayer />
      <FlowerPetals />
      
      {/* 1. Hero */}
      <section id="home" className="relative h-screen flex flex-col items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0"><ThreeRings /></div>
        <div className="text-center z-10">
          <h1 className="text-6xl md:text-9xl font-serif text-luxury-gold italic" data-aos="zoom-in">
            Prabha & Empty
          </h1>
          <p className="text-luxury-dark tracking-[0.6em] uppercase text-[10px] mt-6 opacity-70">
            Inviting You To Celebrate
          </p>
        </div>
      </section>
      
      {/* 2. Timer */}
      <div id="countdown" className="py-16 bg-white shadow-inner relative z-10">
        <Countdown targetDate="2026-12-04" />
      </div>

      {/* 3. Profiles (Bride & Groom) */}
      <Profiles />

      {/* 4. Love Story */}
      <section id="story" className="py-24 max-w-5xl mx-auto px-6">
        <h2 className="text-center font-serif text-5xl italic mb-16">Our Journey</h2>
        <Timeline />
      </section>

      {/* 5. Events Schedule */}
      <Events />

      {/* 6. Photo Gallery */}
      <section id="gallery" className="py-12 bg-white">
        <Gallery />
      </section>

      {/* 7. Venue Map */}
      <VenueMap />

      {/* 8. Gift Registry */}
      <GiftRegistry />

      {/* 9. RSVP Section */}
      <section id="rsvp" className="py-24 bg-[#1A1A1B] text-white overflow-hidden">
        {!submittedData ? (
          <RSVPForm onSubmissionSuccess={setSubmittedData} />
        ) : (
          <div className="flex flex-col items-center py-10" data-aos="zoom-out">
             <h2 className="font-serif text-4xl mb-4 italic">You're on the list!</h2>
             <InvitationQR guestName={submittedData.name} />
          </div>
        )}
      </section>

      {/* 10. Footer */}
      <footer className="py-16 text-center bg-[#FAF9F6]">
        <div className="font-serif italic text-3xl text-luxury-dark mb-4">P & E</div>
        <p className="text-gray-400 uppercase tracking-[0.4em] text-[9px]">With Love — 2030</p>
      </footer>
    </div>
  );
  return (
    <div className="bg-[#FAF9F6] min-h-screen">
      <Navbar />
      <MusicPlayer />
      <FlowerPetals />
      
      <Hero />
      <Countdown targetDate="2026-12-04" />
      
      <Profiles />

      {/* Added Parallax for visual break */}
      <ParallaxSection />

      <section id="story" className="py-24 max-w-5xl mx-auto px-6">
        <Timeline />
      </section>

      <Events />
      
      <Gallery />
      
      {/* Added Guestbook before the RSVP */}
      <Guestbook />

      <VenueMap />
      <GiftRegistry />

      <section id="rsvp" className="py-24 bg-[#1A1A1B] text-white">
        {!submittedData ? (
          <RSVPForm onSubmissionSuccess={setSubmittedData} />
        ) : (
          <div className="flex flex-col items-center py-10">
             <h2 className="font-serif text-4xl mb-4 italic text-luxury-gold">See You Soon!</h2>
             <InvitationQR guestName={submittedData.name} />
          </div>
        )}
      </section>

      <footer className="py-16 text-center bg-[#FAF9F6]">
        <div className="font-serif italic text-3xl text-luxury-dark mb-4">P & E</div>
        <p className="text-gray-400 uppercase tracking-[0.4em] text-[9px]">With Love — 2030</p>
      </footer>
    </div>
  );
  return (
    <div className="bg-[#FAF9F6] min-h-screen relative">
      <Navbar />
      <MusicPlayer />
      <FlowerPetals />
      <FloatingActions /> {/* Global Floating Buttons */}
      
      {/* 1. Enhanced Hero */}
      <section id="home" className="relative h-screen flex flex-col items-center justify-center">
        <div className="absolute inset-0 z-0"><ThreeRings /></div>
        <div className="text-center z-10 space-y-8">
          <h1 className="text-6xl md:text-9xl font-serif text-luxury-gold italic" data-aos="zoom-in">
            Prabha & Empty
          </h1>
          {/* Glass Countdown inside Hero */}
          <div data-aos="fade-up" data-aos-delay="400">
            <GlassCountdown targetDate="2026-12-04" />
          </div>
        </div>
      </section>
      
      <Profiles />
      <ParallaxSection />
      <section id="story" className="py-24 max-w-5xl mx-auto px-6"><Timeline /></section>
      <Events />
      <Gallery />
      <Guestbook />
      <VenueMap />
      <GiftRegistry />

      <section id="rsvp" className="py-24 bg-[#1A1A1B] text-white">
        {!submittedData ? (
          <RSVPForm onSubmissionSuccess={setSubmittedData} />
        ) : (
          <div className="flex flex-col items-center py-10">
             <h2 className="font-serif text-4xl mb-4 italic text-luxury-gold">Ready for the Celebration!</h2>
             <InvitationQR guestName={submittedData.name} />
          </div>
        )}
      </section>

      <footer className="py-16 text-center">
        <div className="font-serif italic text-3xl text-luxury-dark mb-4">P & E</div>
        <p className="text-gray-400 uppercase tracking-[0.4em] text-[9px]">Together Forever — 2030</p>
      </footer>
    </div>
  );
return (
    <div className="bg-[#FAF9F6] min-h-screen relative">
      <Navbar />
      <MusicPlayer />
      <FlowerPetals />
      <FloatingActions />
      
      <Hero />
      <Countdown targetDate="2026-12-04" />
      
      <Profiles />
      <ParallaxSection />
      
      <section id="story" className="py-24 max-w-5xl mx-auto px-6">
        <Timeline />
      </section>

      <Events />
      <Gallery />
      
      {/* New Ultimate Sections */}
      <StyleGuide />
      <LiveCounter />
      
      <Guestbook />
      <VenueMap />
      <GiftRegistry />

      <section id="rsvp" className="py-24 bg-[#1A1A1B] text-white">
        {!submittedData ? (
          <RSVPForm onSubmissionSuccess={setSubmittedData} />
        ) : (
          <div className="flex flex-col items-center py-10" data-aos="zoom-out">
             <h2 className="font-serif text-4xl mb-4 italic text-luxury-gold">You're Registered!</h2>
             <InvitationQR guestName={submittedData.name} />
          </div>
        )}
      </section>

      <footer className="py-16 text-center">
        <div className="font-serif italic text-3xl text-luxury-dark mb-4">P & E</div>
        <p className="text-gray-400 uppercase tracking-[0.4em] text-[9px]">With Love — 2030</p>
      </footer>
    </div>
  );
}


export default App;
